import type { CareerQuestion } from "./rrt-questions";

export const sonographyQuestionsBatch9: CareerQuestion[] = [
  { id: "sono-706", stem: "Anencephaly on prenatal ultrasound is characterized by:", options: ["Absence of the cranial vault and cerebral hemispheres above the orbits","Enlarged head with dilated ventricles","Normal brain with choroid plexus cysts","Banana-shaped cerebellum"], correctIndex: 0, rationale: "Anencephaly is a lethal neural tube defect with absent cranial vault (acrania) and cerebral hemispheres. The face, brainstem, and orbits are present. Detectable in the first trimester; elevated MSAFP.", difficulty: 1, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-707", stem: "The 'lemon sign' on fetal ultrasound refers to:", options: ["Concave frontal bones giving the skull a lemon-shaped appearance, associated with spina bifida","Dilated renal pelvis","Echogenic bowel","Cleft lip"], correctIndex: 0, rationale: "The lemon sign is a frontal bone scalloping seen in the second trimester with open spina bifida (Chiari II malformation). Sensitivity is high in the second trimester but decreases after 24 weeks as cranial shape normalizes.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-708", stem: "The 'banana sign' on fetal ultrasound indicates:", options: ["Anterior curvature and effacement of the cerebellum seen in Chiari II malformation associated with spina bifida","Normal cerebellar shape","Dandy-Walker malformation","Holoprosencephaly"], correctIndex: 0, rationale: "The banana sign is a curved, flattened cerebellum caused by downward herniation of posterior fossa contents in Chiari II malformation. It accompanies the lemon sign and is a key marker for open spina bifida.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-709", stem: "Spina bifida on prenatal ultrasound is best detected by:", options: ["Demonstrating splaying of the posterior ossification centers of the vertebral body in the transverse view","Measuring biparietal diameter alone","Sagittal view of the face","Abdominal circumference measurement"], correctIndex: 0, rationale: "Open spina bifida shows divergent (splayed) posterior ossification centers on transverse views, with a protruding meningocele/myelomeningocele. Associated cranial signs (lemon and banana signs) aid detection.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-710", stem: "Dandy-Walker malformation on fetal ultrasound shows:", options: ["Absent or hypoplastic cerebellar vermis with a large posterior fossa cyst communicating with the fourth ventricle","Normal cerebellum with choroid plexus cyst","Banana-shaped cerebellum","Absent corpus callosum only"], correctIndex: 0, rationale: "Dandy-Walker malformation: complete or partial agenesis of the cerebellar vermis, cystic dilation of the fourth ventricle, and enlarged posterior fossa with upward displacement of the tentorium. Associated with hydrocephalus in 80%.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-711", stem: "Holoprosencephaly on fetal ultrasound is characterized by:", options: ["Failure of the prosencephalon to divide, resulting in a single midline ventricle with fused thalami and facial anomalies","Normal ventricular system with choroid plexus cysts","Posterior fossa cyst","Isolated ventriculomegaly"], correctIndex: 0, rationale: "Holoprosencephaly represents failure of forebrain division. Alobar (most severe): single ventricle, fused thalami, absent falx, cyclopia or proboscis. Semilobar and lobar forms have partial division. Associated with trisomy 13.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-712", stem: "Fetal ventriculomegaly is defined as a lateral ventricular atrial measurement exceeding:", options: ["10mm at the level of the atrium","5mm","15mm","20mm"], correctIndex: 0, rationale: "Fetal lateral ventricular atrial width >10mm defines ventriculomegaly. Mild (10-12mm), moderate (12-15mm), severe (>15mm). Normal is <10mm throughout pregnancy. Associated with chromosomal anomalies, CNS malformations, and infections.", difficulty: 1, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-713", stem: "Agenesis of the corpus callosum on fetal ultrasound shows:", options: ["Teardrop-shaped lateral ventricles (colpocephaly), absent cavum septum pellucidum, and 'sunburst' pattern of sulci radiating from the third ventricle","Normal ventricular configuration","Posterior fossa cyst only","Banana-shaped cerebellum"], correctIndex: 0, rationale: "Absent corpus callosum causes widely spaced lateral ventricles, colpocephaly (dilated occipital horns), high-riding third ventricle, absent cavum septum pellucidum, and radial sulcal pattern. Associated with other CNS and chromosomal anomalies.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-714", stem: "Choroid plexus cysts on fetal ultrasound are:", options: ["Common findings (1-2% of second-trimester fetuses) that are usually benign but may be associated with trisomy 18 when other markers are present","Always pathologic requiring immediate intervention","Never associated with chromosomal abnormalities","Only found in the third trimester"], correctIndex: 0, rationale: "Choroid plexus cysts are found in 1-2% of second-trimester fetuses. Isolated CPCs are generally benign and resolve by 26-28 weeks. When combined with other markers (hand abnormalities, cardiac defects), they raise concern for trisomy 18.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-715", stem: "Congenital diaphragmatic hernia (CDH) on fetal ultrasound shows:", options: ["Abdominal organs (stomach, bowel, liver) in the thorax with mediastinal shift and absent normal diaphragm contour","Enlarged fetal heart only","Pleural effusion without organ herniation","Normal thorax with abdominal wall defect"], correctIndex: 0, rationale: "CDH involves herniation of abdominal organs through the diaphragm (usually left-sided Bochdalek type). Ultrasound shows stomach/bowel/liver in the chest, mediastinal shift to the opposite side, and polyhydramnios. Lung hypoplasia is the major concern.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-716", stem: "Omphalocele on fetal ultrasound is differentiated from gastroschisis by:", options: ["A membrane-covered midline defect at the umbilical cord insertion that may contain liver, covered by peritoneum and amnion","Right-sided defect with free-floating bowel without covering membrane","Left-sided defect below the umbilicus","Defect at the bladder level"], correctIndex: 0, rationale: "Omphalocele: midline, membrane-covered, at umbilical insertion, may contain liver and bowel. Associated with chromosomal abnormalities (trisomy 13, 18). Gastroschisis: right paraumbilical, no covering, bowel only, not chromosomally associated.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-717", stem: "Gastroschisis on fetal ultrasound is characterized by:", options: ["Free-floating bowel herniated through a right paraumbilical abdominal wall defect without a covering membrane","Midline membrane-covered mass at the umbilicus","Left-sided defect with liver herniation","Defect at the level of the bladder"], correctIndex: 0, rationale: "Gastroschisis is a right paraumbilical full-thickness defect with bowel herniating freely into amniotic fluid (no membrane). Usually an isolated anomaly, not chromosomally associated. Bowel may become thickened and matted from amniotic exposure.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-718", stem: "Fetal hydrops on ultrasound is defined as:", options: ["Abnormal fluid accumulation in two or more fetal compartments (skin edema, ascites, pleural effusion, pericardial effusion)","Single pleural effusion alone","Increased amniotic fluid","Placental thickening only"], correctIndex: 0, rationale: "Hydrops fetalis: fluid in ≥2 body cavities (ascites, pleural effusion, pericardial effusion, skin edema >5mm). Immune hydrops from Rh isoimmunization. Non-immune causes include cardiac anomalies, anemia, infection, and chromosomal abnormalities.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-719", stem: "Cystic hygroma on fetal ultrasound appears as:", options: ["Septated cystic mass in the posterior nuchal region, associated with Turner syndrome (45,X) and other chromosomal abnormalities","Solid hyperechoic neck mass","Intracranial cyst","Abdominal wall defect"], correctIndex: 0, rationale: "Cystic hygroma is a lymphatic malformation appearing as a septated cystic mass posterolateral in the fetal neck. Strongly associated with Turner syndrome (45,X), trisomy 21, 18, and 13. May progress to hydrops.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-720", stem: "Fetal sacrococcygeal teratoma on ultrasound appears as:", options: ["Mixed solid and cystic mass arising from the fetal coccyx, varying from predominantly cystic to predominantly solid","Isolated ascites","Posterior fossa cyst","Renal mass"], correctIndex: 0, rationale: "Sacrococcygeal teratoma is the most common fetal tumor. It arises from the coccyx and varies from predominantly cystic (better prognosis) to solid (higher malignancy risk). Large tumors can cause high-output heart failure and hydrops.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-721", stem: "Bilateral renal agenesis (Potter syndrome) on fetal ultrasound shows:", options: ["Absent kidneys bilaterally, absent bladder filling, and severe oligohydramnios","Normal kidneys with polyhydramnios","Bilateral hydronephrosis","Enlarged echogenic kidneys"], correctIndex: 0, rationale: "Bilateral renal agenesis is lethal: absent kidneys and bladder, severe oligohydramnios (no fetal urine), pulmonary hypoplasia. Adrenal glands may mimic kidneys ('lying down' adrenal sign). Confirmation requires visualizing empty renal fossae.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-722", stem: "Multicystic dysplastic kidney (MCDK) on fetal ultrasound appears as:", options: ["Enlarged kidney with multiple non-communicating cysts of varying sizes without identifiable normal renal parenchyma","Single simple renal cyst","Normal kidney with dilated pelvis","Small echogenic kidney"], correctIndex: 0, rationale: "MCDK shows multiple non-communicating cysts of varying sizes replacing the kidney. No normal parenchyma or communication between cysts (unlike hydronephrosis). Often unilateral; contralateral kidney may have compensatory hypertrophy.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-723", stem: "Autosomal recessive polycystic kidney disease (ARPKD) on fetal ultrasound shows:", options: ["Bilaterally enlarged, hyperechoic kidneys with loss of corticomedullary differentiation and oligohydramnios","Normal-sized kidneys with single cyst","Small kidneys with calcification","Unilateral hydronephrosis"], correctIndex: 0, rationale: "ARPKD causes bilaterally enlarged, hyperechoic kidneys (microcysts too small to resolve) with oligohydramnios. Associated with congenital hepatic fibrosis. Lethal in severe forms due to pulmonary hypoplasia.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-724", stem: "Fetal posterior urethral valves on ultrasound show:", options: ["Dilated posterior urethra ('keyhole sign'), bilateral hydronephrosis, distended bladder, and possible oligohydramnios","Normal bladder and kidneys","Unilateral renal agenesis","Echogenic bowel only"], correctIndex: 0, rationale: "Posterior urethral valves (males only) cause bladder outlet obstruction: keyhole sign (dilated proximal urethra), thick-walled distended bladder, bilateral hydroureteronephrosis, and oligohydramnios in severe cases.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-725", stem: "Fetal tetralogy of Fallot on ultrasound demonstrates:", options: ["Overriding aorta, ventricular septal defect, right ventricular hypertrophy, and pulmonary stenosis","Normal four-chamber view","Single ventricle","Transposed great vessels"], correctIndex: 0, rationale: "TOF: VSD with overriding aorta, right ventricular outflow tract obstruction (pulmonary stenosis), and RV hypertrophy. The outflow tract view shows the aorta straddling the ventricular septum. Most common cyanotic congenital heart defect.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-726", stem: "A single umbilical artery (SUA) on fetal ultrasound is associated with:", options: ["Increased risk of renal anomalies, cardiac defects, and chromosomal abnormalities","No clinical significance","Gestational diabetes","Normal variant with no risk increase"], correctIndex: 0, rationale: "SUA occurs in ~1% of pregnancies. Isolated SUA has a low but increased risk of renal, cardiac, and GI anomalies. When associated with other anomalies, chromosomal abnormality risk increases. The absent artery is usually the left.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-727", stem: "Echogenic intracardiac focus (EIF) on fetal ultrasound:", options: ["Is a common normal variant but can be a soft marker for trisomy 21 when present with other markers","Always indicates a cardiac defect requiring surgery","Is never seen in normal fetuses","Indicates fetal arrhythmia"], correctIndex: 0, rationale: "EIF is a bright focus in the fetal ventricle (usually left) representing papillary muscle calcification. Isolated EIF in low-risk patients is benign. Combined with other soft markers or risk factors, it may increase trisomy 21 risk.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-728", stem: "Echogenic fetal bowel is significant because:", options: ["It can be associated with cystic fibrosis, trisomy 21, fetal swallowed blood, CMV infection, or IUGR","It is always a normal finding","It only indicates meconium peritonitis","It resolves by itself in all cases"], correctIndex: 0, rationale: "Echogenic bowel (as bright as bone) has multiple associations: cystic fibrosis (meconium ileus), trisomy 21, CMV/toxoplasmosis, swallowed blood, and IUGR. Requires further evaluation with CF screening and genetic counseling.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-729", stem: "Fetal duodenal atresia on ultrasound shows:", options: ["'Double bubble' sign with dilated stomach and proximal duodenum, associated with trisomy 21","Single fluid collection in the abdomen","Echogenic bowel only","Normal bowel pattern"], correctIndex: 0, rationale: "Duodenal atresia creates the 'double bubble' sign: dilated fluid-filled stomach and proximal duodenum separated by the pylorus. Polyhydramnios is common. About 30% are associated with trisomy 21.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-730", stem: "Thanatophoric dysplasia on fetal ultrasound shows:", options: ["Severe micromelia with 'telephone receiver' curved femurs, narrow thorax, macrocephaly, and frontal bossing","Normal limb length with large abdomen","Absent limbs entirely","Isolated short femur"], correctIndex: 0, rationale: "Thanatophoric dysplasia is the most common lethal skeletal dysplasia. Features include severe micromelia, curved femurs (telephone receiver shape), narrow bell-shaped thorax, macrocephaly with cloverleaf skull, and polyhydramnios.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-731", stem: "Placenta previa is diagnosed on ultrasound when:", options: ["The placenta covers or is within 2cm of the internal cervical os after 16 weeks","The placenta is fundal","The placenta is lateral on the uterine wall","The umbilical cord inserts marginally"], correctIndex: 0, rationale: "Placenta previa: placenta covering (complete) or within 2cm of the internal os. Diagnosed definitively after 16-20 weeks (early low-lying placenta may migrate). Transvaginal ultrasound is the gold standard for diagnosis.", difficulty: 1, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-732", stem: "Placenta accreta spectrum on ultrasound shows:", options: ["Loss of the normal retroplacental hypoechoic zone, placental lacunae, and increased vascularity at the uterine-bladder interface","Normal retroplacental zone","Thick retroplacental hematoma","Calcified placenta"], correctIndex: 0, rationale: "Placenta accreta spectrum (accreta, increta, percreta): loss of retroplacental clear space, placental lacunae ('Swiss cheese' pattern), bulging of placenta into bladder (percreta), and turbulent flow at serosa-bladder interface on Doppler.", difficulty: 4, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-733", stem: "Placental abruption on ultrasound may show:", options: ["Retroplacental or subchorionic hematoma, though ultrasound sensitivity is only 25-50%","Always a visible hematoma","Normal placental appearance rules out abruption","Calcified placenta"], correctIndex: 0, rationale: "Abruption may show retroplacental, subchorionic, or marginal hematoma. Acute blood is iso/hyperechoic to placenta and may be missed. Ultrasound sensitivity is only 25-50%; clinical diagnosis (pain, bleeding, fetal distress) is primary.", difficulty: 3, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-734", stem: "A succenturiate (accessory) placental lobe is significant because:", options: ["Vessels connecting the lobes may cross the internal os (vasa previa), risking fatal hemorrhage at membrane rupture","It has no clinical significance","It always causes placental abruption","It indicates multiple gestation"], correctIndex: 0, rationale: "Succenturiate lobe is an accessory lobe connected to the main placenta by membranes containing vessels. If these vessels cross the internal os (vasa previa), rupture of membranes can cause fetal hemorrhage with high mortality.", difficulty: 3, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-735", stem: "Vasa previa on ultrasound is diagnosed by:", options: ["Color Doppler showing fetal vessels crossing or running within 2cm of the internal cervical os","B-mode imaging of the cervix alone","Measuring cervical length","Amniotic fluid assessment"], correctIndex: 0, rationale: "Vasa previa: unprotected fetal vessels cross the internal os. Color Doppler identifies vessels over the os (confirm with pulsed Doppler showing fetal heart rate). Risk factors include succenturiate lobe, velamentous insertion, and low-lying placenta.", difficulty: 4, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-736", stem: "Velamentous cord insertion on ultrasound shows:", options: ["Umbilical vessels inserting into the fetal membranes rather than the placental disc, with vessels running through membranes to reach the placenta","Normal central cord insertion","Marginal cord insertion","Battledore placenta"], correctIndex: 0, rationale: "Velamentous insertion: cord inserts into membranes, and unprotected vessels course through membranes to the placental edge. Risk of vasa previa, vessel compression, and hemorrhage. Color Doppler confirms membrane vessel location.", difficulty: 3, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-737", stem: "Placental chorioangioma on ultrasound appears as:", options: ["Well-defined hypoechoic or complex mass on the fetal surface of the placenta with prominent vascularity on Doppler","Calcified focus within the placenta","Normal placental variant","Retroplacental hematoma"], correctIndex: 0, rationale: "Chorioangioma is the most common non-trophoblastic placental tumor. Large ones (>4-5cm) may cause polyhydramnios, fetal anemia, hydrops, and high-output cardiac failure due to arteriovenous shunting. Color Doppler shows feeding vessels.", difficulty: 4, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-738", stem: "A circumvallate placenta on ultrasound shows:", options: ["Inward folding of the placental membranes creating a rolled edge with the chorionic plate smaller than the basal plate","Normal flat placental margins","Central placental mass","Thickened placental cord insertion"], correctIndex: 0, rationale: "Circumvallate placenta: membranes fold inward creating a thick rolled edge. Associated with antepartum hemorrhage, preterm delivery, and placental abruption. The chorionic plate is smaller than the basal plate.", difficulty: 4, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-739", stem: "Placental thickness should normally not exceed:", options: ["4cm at any gestational age; thickening suggests hydrops, infection, diabetes, or Rh isoimmunization","2cm","6cm","8cm"], correctIndex: 0, rationale: "Normal placental thickness approximates gestational age in mm (±10mm) but should not exceed 4cm. Thick placenta (>4cm) suggests hydrops fetalis, gestational diabetes, Rh isoimmunization, infection, or triploidy.", difficulty: 2, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-740", stem: "Placental grading (Grannum classification) Grade III shows:", options: ["Indentations extending to the basal plate creating cotyledons, with echogenic areas representing calcification","Smooth chorionic plate without calcification","Subtle undulations of the chorionic plate","Homogeneous placental substance"], correctIndex: 0, rationale: "Grade III: complete indentations from chorionic plate to basal plate dividing placenta into cotyledons, with basal calcification. Before 34 weeks, Grade III may indicate placental insufficiency and increased perinatal risk.", difficulty: 3, category: "OB/GYN Sonography", topic: "Placental Pathology" },
  { id: "sono-741", stem: "Polyhydramnios is defined as an amniotic fluid index (AFI) greater than:", options: ["24-25cm or single deepest pocket >8cm","15cm","10cm","30cm"], correctIndex: 0, rationale: "Polyhydramnios: AFI >24-25cm or single deepest pocket >8cm. Causes include fetal GI obstruction, neural tube defects, diabetes, fetal anemia, twin-twin transfusion (recipient), and idiopathic (60%). Mild is AFI 25-30cm.", difficulty: 1, category: "OB/GYN Sonography", topic: "Amniotic Fluid" },
  { id: "sono-742", stem: "Oligohydramnios is defined as an AFI less than:", options: ["5cm or single deepest pocket <2cm","10cm","15cm","20cm"], correctIndex: 0, rationale: "Oligohydramnios: AFI <5cm or single deepest pocket <2cm. Causes include PPROM, renal agenesis, posterior urethral valves, IUGR, and post-dates pregnancy. Risk of pulmonary hypoplasia and cord compression.", difficulty: 1, category: "OB/GYN Sonography", topic: "Amniotic Fluid" },
  { id: "sono-743", stem: "The amniotic fluid index (AFI) is measured by:", options: ["Summing the single deepest vertical pocket in each of four uterine quadrants without including cord or fetal parts","Measuring a single pocket in one quadrant","Estimating fluid volume by eye","Measuring the largest single pocket only"], correctIndex: 0, rationale: "AFI is calculated by dividing the uterus into four quadrants using the linea nigra and umbilicus, then summing the deepest vertical pocket in each quadrant (measured perpendicular to the floor, excluding cord/fetal parts). Normal is 5-24cm.", difficulty: 1, category: "OB/GYN Sonography", topic: "Amniotic Fluid" },
  { id: "sono-744", stem: "Amniotic band syndrome on fetal ultrasound shows:", options: ["Bands of amniotic tissue attached to fetal parts causing constriction, amputation, or asymmetric defects","Symmetric limb shortening","Bilateral clubfeet without bands","Normal fetal anatomy"], correctIndex: 0, rationale: "Amniotic band syndrome results from rupture of the amnion with bands entangling fetal parts. Features include asymmetric limb constrictions/amputations, craniofacial clefts not following embryologic lines, and abdominal wall defects.", difficulty: 3, category: "OB/GYN Sonography", topic: "Amniotic Fluid" },
  { id: "sono-745", stem: "Twin-to-twin transfusion syndrome (TTTS) in monochorionic twins shows:", options: ["Polyhydramnios in the recipient twin and oligohydramnios in the donor twin ('stuck twin')","Equal amniotic fluid in both sacs","Both twins with polyhydramnios","Normal fluid with discordant fetal sizes only"], correctIndex: 0, rationale: "TTTS occurs in monochorionic-diamniotic twins with unbalanced arteriovenous anastomoses. Donor: oligohydramnios, small/stuck twin, empty bladder. Recipient: polyhydramnios, large twin, distended bladder, possible hydrops.", difficulty: 3, category: "OB/GYN Sonography", topic: "Amniotic Fluid" },
  { id: "sono-746", stem: "The biophysical profile (BPP) includes which five components?", options: ["Fetal breathing movements, gross body movements, fetal tone, amniotic fluid volume (AFI), and non-stress test (NST)","Only non-stress test and AFI","Only fetal heart rate and movement","Doppler of umbilical artery and fetal heart rate"], correctIndex: 0, rationale: "The BPP scores five parameters (2 points each, max 10): fetal breathing (≥30s in 30min), gross movements (≥3 in 30min), fetal tone (extension/flexion), AFV (pocket ≥2cm), and NST (reactive). Score ≤4 warrants delivery consideration.", difficulty: 1, category: "OB/GYN Sonography", topic: "Biophysical Profile" },
  { id: "sono-747", stem: "A biophysical profile score of 8/10 with normal amniotic fluid indicates:", options: ["Normal, non-asphyxiated fetus; routine management","Immediate delivery required","Fetal distress","Repeat testing in 2 hours"], correctIndex: 0, rationale: "BPP 8/10 with normal AFV is reassuring (risk of fetal death within 1 week is <1/1000). BPP 6/10 is equivocal. BPP ≤4/10 suggests asphyxia and may warrant delivery. Abnormal AFV is concerning regardless of other scores.", difficulty: 1, category: "OB/GYN Sonography", topic: "Biophysical Profile" },
  { id: "sono-748", stem: "The modified biophysical profile consists of:", options: ["Non-stress test (NST) and amniotic fluid index (AFI)","Full five-component BPP","Only Doppler assessment","Only fetal movement counting"], correctIndex: 0, rationale: "The modified BPP combines NST (short-term marker of fetal status) and AFI (long-term marker of placental function). It is simpler and faster than the full BPP while maintaining good predictive value.", difficulty: 2, category: "OB/GYN Sonography", topic: "Biophysical Profile" },
  { id: "sono-749", stem: "Fetal breathing movements on BPP are considered present when:", options: ["At least one episode of rhythmic breathing lasting 30 seconds or more within a 30-minute observation period","Continuous breathing for 5 minutes","Any single breath detected","Breathing for the entire observation period"], correctIndex: 0, rationale: "BPP criteria for breathing: ≥1 episode of sustained rhythmic breathing ≥30 seconds within 30 minutes of observation. Fetal breathing movements may be absent during fetal sleep cycles, after maternal medication, or in hypoxia.", difficulty: 2, category: "OB/GYN Sonography", topic: "Biophysical Profile" },
  { id: "sono-750", stem: "Fetal tone on BPP is scored as normal when:", options: ["At least one episode of active extension with return to flexion of limbs or trunk, or hand opening and closing","Persistent extension of extremities","No movement observed","Only limb movement without flexion return"], correctIndex: 0, rationale: "Normal fetal tone (2 points): ≥1 episode of extension-flexion of limb/trunk or hand opening-closing. Tone is the last BPP variable to become abnormal in progressive fetal hypoxia, making its absence the most ominous sign.", difficulty: 2, category: "OB/GYN Sonography", topic: "Biophysical Profile" },
  { id: "sono-751", stem: "In progressive fetal hypoxia, the order of BPP variable loss is:", options: ["NST reactivity → breathing movements → gross body movements → fetal tone","Fetal tone → breathing → movements → NST","All variables are lost simultaneously","AFI → tone → breathing → NST"], correctIndex: 0, rationale: "Progressive hypoxia causes sequential loss of BPP variables in order of their CNS maturation (last acquired = first lost): heart rate reactivity (NST), breathing, body movements, then tone. AFI reflects chronic placental function.", difficulty: 4, category: "OB/GYN Sonography", topic: "Biophysical Profile" },
  { id: "sono-752", stem: "Normal umbilical artery Doppler in the third trimester shows:", options: ["Continuous forward diastolic flow with a systolic/diastolic ratio that decreases as pregnancy advances","Absent end-diastolic flow","Reversed diastolic flow","High-resistance flow with no diastolic component"], correctIndex: 0, rationale: "Normal umbilical artery shows low-resistance flow with continuous forward diastolic flow that increases as placental vascular resistance decreases through pregnancy. S/D ratio decreases from ~4.0 at 20 weeks to ~2.0-3.0 at term.", difficulty: 2, category: "OB/GYN Sonography", topic: "Doppler Assessment" },
  { id: "sono-753", stem: "Absent end-diastolic flow (AEDF) in the umbilical artery indicates:", options: ["Significantly increased placental vascular resistance with high risk of fetal compromise and potential need for delivery","Normal placental function","Improved fetal oxygenation","Decreased placental resistance"], correctIndex: 0, rationale: "AEDF indicates markedly elevated placental resistance. Associated with IUGR, placental insufficiency, and increased perinatal morbidity/mortality. Requires close surveillance with possible delivery depending on gestational age.", difficulty: 3, category: "OB/GYN Sonography", topic: "Doppler Assessment" },
  { id: "sono-754", stem: "Reversed end-diastolic flow (REDF) in the umbilical artery signifies:", options: ["Critical fetal compromise with extremely high placental resistance and a strong indication for delivery","Mildly elevated placental resistance","Normal Doppler finding in early pregnancy","Decreased placental resistance"], correctIndex: 0, rationale: "REDF is the most ominous umbilical artery Doppler finding, indicating severely elevated placental resistance. Associated with high perinatal mortality (>50% in some series). Delivery is usually indicated regardless of gestational age.", difficulty: 3, category: "OB/GYN Sonography", topic: "Doppler Assessment" },
  { id: "sono-755", stem: "Middle cerebral artery (MCA) Doppler peak systolic velocity is used to:", options: ["Non-invasively detect fetal anemia by showing elevated PSV correlating with decreased blood viscosity","Assess placental resistance","Measure amniotic fluid production","Evaluate fetal cardiac output"], correctIndex: 0, rationale: "MCA-PSV >1.5 MoM indicates moderate to severe fetal anemia (sensitivity ~100% for severe anemia). Decreased blood viscosity from anemia causes increased velocity. Used in Rh isoimmunization, parvovirus B19 infection, and TTTS.", difficulty: 3, category: "OB/GYN Sonography", topic: "Doppler Assessment" },
  { id: "sono-756", stem: "The cerebroplacental ratio (CPR) is calculated by:", options: ["MCA pulsatility index divided by umbilical artery pulsatility index, with low values suggesting fetal brain-sparing","Umbilical artery PI divided by MCA PI","MCA PSV divided by umbilical artery PSV","Fetal heart rate divided by maternal heart rate"], correctIndex: 0, rationale: "CPR = MCA PI / UA PI. Low CPR (<1.0 or <5th percentile) indicates redistribution of cardiac output to the brain (brain-sparing effect) in response to placental insufficiency. It is a sensitive marker of fetal compromise.", difficulty: 4, category: "OB/GYN Sonography", topic: "Doppler Assessment" },
  { id: "sono-757", stem: "Ductus venosus Doppler in a compromised fetus showing absent or reversed a-wave indicates:", options: ["Cardiac decompensation with increased risk of acidemia and fetal demise, often a pre-terminal finding","Normal cardiac function","Improved fetal status","Decreased placental resistance"], correctIndex: 0, rationale: "The ductus venosus a-wave reflects atrial contraction. Absent or reversed a-wave indicates elevated central venous pressure and cardiac dysfunction. It is a late finding in the deterioration sequence and often precedes fetal death.", difficulty: 4, category: "OB/GYN Sonography", topic: "Doppler Assessment" },
  { id: "sono-758", stem: "Uterine artery Doppler with bilateral notching after 24 weeks suggests:", options: ["Increased risk of preeclampsia and intrauterine growth restriction due to inadequate trophoblastic invasion","Normal uteroplacental circulation","Fetal anemia","Polyhydramnios"], correctIndex: 0, rationale: "Persistent bilateral uterine artery notching after 24 weeks indicates failed trophoblastic invasion of spiral arteries, maintaining high-resistance flow. This increases the risk of preeclampsia, IUGR, and placental abruption.", difficulty: 3, category: "OB/GYN Sonography", topic: "Doppler Assessment" },
  { id: "sono-759", stem: "Normal uterine artery Doppler waveform in the second and third trimesters shows:", options: ["Low-resistance flow with continuous forward diastolic flow and absence of an early diastolic notch","High-resistance flow with absent diastolic flow","Reversed diastolic flow","Monophasic flow with notching"], correctIndex: 0, rationale: "Normal uterine artery flow becomes low-resistance by 24 weeks due to trophoblastic invasion converting spiral arteries into low-resistance vessels. The early diastolic notch normally disappears by 24 weeks.", difficulty: 2, category: "OB/GYN Sonography", topic: "Doppler Assessment" },
  { id: "sono-760", stem: "Fetal MCA Doppler showing decreased pulsatility index (brain-sparing) indicates:", options: ["Cerebral vasodilation in response to hypoxia, redistributing blood flow preferentially to the brain","Normal cerebral blood flow","Fetal hyperoxia","Increased placental perfusion"], correctIndex: 0, rationale: "Brain-sparing: cerebral vasodilation (decreased MCA PI) occurs when the fetus preferentially shunts blood to vital organs (brain, heart, adrenals) in response to hypoxia/placental insufficiency. MCA PI <5th percentile is abnormal.", difficulty: 3, category: "OB/GYN Sonography", topic: "Doppler Assessment" },
  { id: "sono-761", stem: "Crown-rump length (CRL) is the most accurate dating parameter and is used in:", options: ["The first trimester (up to 13 6/7 weeks) with accuracy of ±3-5 days","The second trimester","The third trimester","Any gestational age"], correctIndex: 0, rationale: "CRL measured between 7-13 6/7 weeks is the most accurate dating parameter (±3-5 days). After the first trimester, BPD, HC, FL, and AC are used but with decreasing accuracy as pregnancy advances.", difficulty: 1, category: "OB/GYN Sonography", topic: "Fetal Biometry" },
  { id: "sono-762", stem: "Intrauterine growth restriction (IUGR) is suspected when:", options: ["Estimated fetal weight or abdominal circumference is below the 10th percentile for gestational age","Biparietal diameter is above the 90th percentile","Femur length is above normal","Amniotic fluid is increased"], correctIndex: 0, rationale: "IUGR: EFW or AC <10th percentile. Symmetric IUGR (early onset, proportional) suggests chromosomal or infectious causes. Asymmetric IUGR (late onset, head-sparing, small abdomen) suggests placental insufficiency.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Biometry" },
  { id: "sono-763", stem: "Macrosomia is defined as estimated fetal weight exceeding:", options: ["4,000-4,500 grams regardless of gestational age","3,000 grams","2,500 grams","5,500 grams"], correctIndex: 0, rationale: "Macrosomia is EFW >4,000g (some use >4,500g). Risk factors include gestational diabetes, maternal obesity, post-dates pregnancy, and multiparity. Complications include shoulder dystocia, birth trauma, and operative delivery.", difficulty: 1, category: "OB/GYN Sonography", topic: "Fetal Biometry" },
  { id: "sono-764", stem: "The fetal biparietal diameter (BPD) is measured at the level of:", options: ["The thalami and cavum septum pellucidum, from outer table of proximal skull to inner table of distal skull","The orbits","The cerebellum","Any axial plane through the skull"], correctIndex: 0, rationale: "BPD is measured at the level of thalami and CSP, from leading edge to leading edge (outer-to-inner). The calvarium should be symmetric and ovoid. BPD is most accurate for dating at 12-20 weeks.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Biometry" },
  { id: "sono-765", stem: "The head circumference (HC) to abdominal circumference (AC) ratio is used to:", options: ["Differentiate symmetric from asymmetric IUGR; elevated HC/AC ratio suggests asymmetric growth restriction with head-sparing","Predict fetal gender","Estimate amniotic fluid volume","Assess fetal lung maturity"], correctIndex: 0, rationale: "HC/AC ratio >95th percentile suggests asymmetric IUGR (head-sparing, small abdomen from depleted liver glycogen). Normal HC/AC ratio with small measurements suggests symmetric IUGR (proportional reduction).", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Biometry" },
  { id: "sono-766", stem: "Cervical length measured by transvaginal ultrasound less than 25mm before 24 weeks is associated with:", options: ["Increased risk of preterm birth","Decreased risk of preterm birth","Post-dates pregnancy","Placenta previa"], correctIndex: 0, rationale: "Short cervix (<25mm by TVS before 24 weeks) is the strongest ultrasound predictor of preterm birth. Cervical length <15mm has the highest risk. Progesterone supplementation and cerclage may be considered in high-risk patients.", difficulty: 2, category: "OB/GYN Sonography", topic: "Cervical Assessment" },
  { id: "sono-767", stem: "Cervical funneling on transvaginal ultrasound refers to:", options: ["Dilation of the internal os with the external os remaining closed, creating a V or U-shaped configuration","Elongation of the cervix","Calcification of the cervix","Cervical mass"], correctIndex: 0, rationale: "Cervical funneling is opening of the internal os while the external os remains closed. The funnel may be V, U, or Y-shaped. When combined with short residual cervical length, it significantly increases preterm birth risk.", difficulty: 3, category: "OB/GYN Sonography", topic: "Cervical Assessment" },
  { id: "sono-768", stem: "A complete molar pregnancy has which chromosomal composition?", options: ["46,XX (all paternal; diploid) from fertilization of an empty ovum by a single sperm that duplicates","69,XXY (triploid)","46,XY (normal)","45,X (Turner syndrome)"], correctIndex: 0, rationale: "Complete mole is usually 46,XX (all paternal/androgenetic). An empty ovum is fertilized by one sperm that duplicates. No fetal tissue present. Risk of GTN is 15-20%. Markedly elevated beta-hCG with snowstorm appearance.", difficulty: 3, category: "OB/GYN Sonography", topic: "Gestational Trophoblastic Disease" },
  { id: "sono-769", stem: "A partial molar pregnancy on ultrasound may show:", options: ["A fetus (often with triploidy) with a large placenta containing focal cystic spaces","No fetal parts with snowstorm pattern","Normal fetus with normal placenta","Empty gestational sac"], correctIndex: 0, rationale: "Partial mole contains fetal tissue (usually triploid, 69,XXX or 69,XXY). The placenta shows focal cystic change (Swiss cheese pattern). Beta-hCG is less elevated than complete mole. Lower risk of GTN (~5%).", difficulty: 3, category: "OB/GYN Sonography", topic: "Gestational Trophoblastic Disease" },
  { id: "sono-770", stem: "Ectopic pregnancy on ultrasound is suggested by:", options: ["Adnexal mass or ring sign separate from the ovary with empty uterus and positive pregnancy test","Intrauterine gestational sac with yolk sac","Normal adnexal appearance in all cases","Bilateral ovarian cysts"], correctIndex: 0, rationale: "Ectopic pregnancy: empty uterus with positive hCG, adnexal mass/ring (tubal ring sign), free fluid in cul-de-sac, and no intrauterine gestational sac when hCG exceeds discriminatory level (1,500-2,000 mIU/mL by TVS).", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-771", stem: "The discriminatory level of beta-hCG for transvaginal ultrasound is:", options: ["1,500-2,000 mIU/mL, above which an intrauterine gestational sac should be visible if pregnancy is intrauterine","500 mIU/mL","10,000 mIU/mL","100 mIU/mL"], correctIndex: 0, rationale: "The discriminatory level is the hCG value above which a normal IUP should be visible on TVS (1,500-2,000 mIU/mL). If hCG is above this level with empty uterus, ectopic pregnancy, early pregnancy loss, or recent miscarriage should be considered.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-772", stem: "A pseudogestational sac in ectopic pregnancy differs from a true gestational sac by:", options: ["Being centrally located in the endometrial cavity without a yolk sac or embryo, representing decidualized endometrium","Having a visible yolk sac","Being eccentric within the endometrium","Showing a double decidual sign"], correctIndex: 0, rationale: "A pseudogestational sac is fluid within the endometrial cavity from decidual reaction. It is centrally located, irregularly shaped, without double decidual sign, yolk sac, or embryo. A true sac is eccentric with double decidual sign.", difficulty: 3, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-773", stem: "The yolk sac should be visible on transvaginal ultrasound when the mean gestational sac diameter reaches:", options: ["8-10mm","2mm","20mm","25mm"], correctIndex: 0, rationale: "The yolk sac should be visible when MSD reaches 8-10mm on TVS. Absence of a yolk sac when MSD >8mm raises concern for early pregnancy failure. The yolk sac provides early nutrition and hematopoiesis.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-774", stem: "Fetal cardiac activity should be visible when the embryonic crown-rump length reaches:", options: ["7mm on transvaginal ultrasound","2mm","15mm","25mm"], correctIndex: 0, rationale: "Cardiac activity should be seen when CRL ≥7mm on TVS. Absence of cardiac activity with CRL ≥7mm is diagnostic of embryonic demise. Normal early embryonic heart rate is 100-120 bpm at 6 weeks, increasing to 140-170 bpm by 9 weeks.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-775", stem: "Subchorionic hemorrhage on first-trimester ultrasound appears as:", options: ["Crescent-shaped hypo- or anechoic collection between the chorion and uterine wall, adjacent to the gestational sac","Hyperechoic mass within the gestational sac","Normal finding without significance","Echogenic fetal bowel"], correctIndex: 0, rationale: "Subchorionic hemorrhage is bleeding between the chorion and endometrium. Small ones are usually benign. Large ones (>50% of sac circumference) increase risk of miscarriage. Echogenicity depends on age of blood.", difficulty: 2, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-776", stem: "Heterotopic pregnancy (simultaneous intrauterine and ectopic pregnancy) is most commonly seen in:", options: ["Patients undergoing assisted reproductive technology (ART), occurring in approximately 1-3% of ART pregnancies","Natural conception at 1:30,000 rate","Patients with IUDs","Postmenopausal women"], correctIndex: 0, rationale: "Heterotopic pregnancy occurs naturally in ~1:30,000 pregnancies but increases to 1-3% with ART/IVF. The presence of an IUP does not exclude an ectopic. Both adnexa should always be evaluated.", difficulty: 3, category: "OB/GYN Sonography", topic: "First Trimester" },
  { id: "sono-777", stem: "Monochorionic-monoamniotic (MCMA) twins on ultrasound show:", options: ["Two fetuses in a single sac without an intervening membrane and a single placenta","Two placentas with thick dividing membrane","Single fetus with two placentas","Two sacs with thick membrane"], correctIndex: 0, rationale: "MCMA twins share one placenta and one amniotic sac (no dividing membrane). Highest-risk twin type due to cord entanglement (100% risk), prematurity, and TTTS. Requires intensive surveillance.", difficulty: 3, category: "OB/GYN Sonography", topic: "Multiple Gestation" },
  { id: "sono-778", stem: "The 'twin peak' or 'lambda sign' on ultrasound indicates:", options: ["Dichorionic placentation with placental tissue projecting into the base of the intertwin membrane","Monochorionic placentation","Monoamniotic twins","Conjoined twins"], correctIndex: 0, rationale: "The twin peak (lambda) sign is a triangular projection of placental tissue at the base of the intertwin membrane, indicating dichorionic (separate) placentas. Best evaluated in the first trimester. Absence suggests monochorionic.", difficulty: 2, category: "OB/GYN Sonography", topic: "Multiple Gestation" },
  { id: "sono-779", stem: "Fetal cleft lip on ultrasound is best detected in:", options: ["Coronal view of the face showing a defect in the upper lip, may extend into the alveolar ridge and palate","Transverse view of the spine","Sagittal view of the trunk","Axial view of the abdomen"], correctIndex: 0, rationale: "Cleft lip is visualized on coronal face views showing a defect in the upper lip. Cleft palate is more difficult to diagnose sonographically. 3D ultrasound improves detection. Associated with trisomy 13 and other syndromes.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-780", stem: "Fetal clubfoot (talipes equinovarus) on ultrasound shows:", options: ["The foot in a fixed perpendicular position to the tibia and fibula, seen in the same plane as the long bones","Normal foot-leg angle","Absent foot","Extra digits"], correctIndex: 0, rationale: "Clubfoot shows the foot and leg in the same plane (persistent plantar flexion and inversion). Normally the foot is at a right angle to the leg. May be isolated or associated with neuromuscular disorders, spina bifida, or chromosomal abnormalities.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-781", stem: "Fetal abdominal circumference (AC) is measured at the level of:", options: ["The umbilical vein-portal sinus junction, stomach bubble, and spine in a true transverse plane","The kidneys","The bladder","Any level of the abdomen"], correctIndex: 0, rationale: "AC is measured at the level of the umbilical vein entering the portal sinus (J-shape), with the stomach bubble visible and spine posterior. The abdomen should be round, not oval, indicating a true transverse section.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Biometry" },
  { id: "sono-782", stem: "A short femur length on fetal ultrasound may be associated with:", options: ["Skeletal dysplasia, trisomy 21, IUGR, or constitutional variation","Only skeletal dysplasia","Always normal variation","Macrosomia"], correctIndex: 0, rationale: "Short femur (<5th percentile) has multiple associations: skeletal dysplasia (achondroplasia, osteogenesis imperfecta), trisomy 21 (soft marker), IUGR, incorrect dating, and normal constitutional short stature.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Biometry" },
  { id: "sono-783", stem: "Fetal pyelectasis is defined as renal pelvic AP diameter exceeding:", options: ["4mm in the second trimester or 7mm in the third trimester","1mm at any age","10mm in the second trimester","15mm at term"], correctIndex: 0, rationale: "Pyelectasis: renal pelvis AP diameter >4mm (second trimester) or >7mm (third trimester). Mild pyelectasis is a soft marker for trisomy 21. Progressive dilation may indicate ureteropelvic junction obstruction.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-784", stem: "Absent nasal bone on first-trimester ultrasound is a marker for:", options: ["Trisomy 21, being present in approximately 60-70% of affected fetuses","Trisomy 18 only","Neural tube defects","Normal variant without significance"], correctIndex: 0, rationale: "Absent nasal bone at 11-14 weeks is a strong marker for trisomy 21 (LR+ 6-7). It is absent in 60-70% of trisomy 21 fetuses vs. 1-2% of euploid fetuses. Combined with NT and serum markers, it improves first-trimester screening.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-785", stem: "Fetal abdominal wall defect at the level of the bladder with a protruding mass suggests:", options: ["Bladder exstrophy, where the bladder is exposed on the anterior abdominal wall","Omphalocele","Gastroschisis","Limb-body wall complex"], correctIndex: 0, rationale: "Bladder exstrophy shows a soft tissue mass at the lower anterior abdominal wall with non-visualization of a normal fluid-filled bladder. Associated with epispadias and widened pubic symphysis. Normal amniotic fluid is present.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-786", stem: "Fetal megacystis in the first trimester (bladder >7mm) is associated with:", options: ["Posterior urethral valves in males or megacystis-microcolon-intestinal hypoperistalsis syndrome, with risk of chromosomal abnormalities","Normal bladder distension","Renal agenesis","Polycystic kidneys"], correctIndex: 0, rationale: "First-trimester megacystis (bladder longitudinal diameter >7mm) is associated with lower urinary tract obstruction (PUV in males), trisomy 13 and 18 (especially with bladder >15mm), and megacystis-microcolon syndrome.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-787", stem: "Fetal aortic coarctation may be suspected on ultrasound when:", options: ["There is significant size discrepancy between the right and left ventricles with a smaller left ventricle and narrow aortic arch","Equal-sized ventricles","Large left ventricle","Absent right ventricle"], correctIndex: 0, rationale: "Aortic coarctation causes left-sided cardiac structures to be smaller (left ventricle, aorta) relative to right-sided structures. Four-chamber view may show ventricular disproportion. Three-vessel view shows discrepancy between aortic and ductal arch sizes.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-788", stem: "Hypoplastic left heart syndrome (HLHS) on fetal ultrasound shows:", options: ["Small left ventricle, aortic and mitral atresia/stenosis, with the right ventricle as the dominant chamber","Enlarged left ventricle","Normal four-chamber view","Transposed great vessels"], correctIndex: 0, rationale: "HLHS: diminutive left ventricle with atresia or severe stenosis of aortic and mitral valves. The four-chamber view shows a dominant right ventricle. The ascending aorta is hypoplastic. Retrograde arch flow via ductus arteriosus.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-789", stem: "Transposition of the great arteries (TGA) on fetal ultrasound is identified by:", options: ["Parallel great vessels arising from the heart instead of the normal crossing pattern, with the aorta arising from the right ventricle","Normal crossing of great vessels","Single great vessel","Absent pulmonary artery"], correctIndex: 0, rationale: "D-TGA: aorta arises from the right ventricle (anterior) and pulmonary artery from the left ventricle (posterior). Great vessels run parallel instead of crossing. The four-chamber view may appear normal, requiring outflow tract views.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-790", stem: "Ebstein anomaly on fetal ultrasound shows:", options: ["Apical displacement of the septal leaflet of the tricuspid valve with massive right atrial enlargement and cardiomegaly","Small right atrium","Ventricular septal defect only","Coarctation of the aorta"], correctIndex: 0, rationale: "Ebstein anomaly: downward displacement of the tricuspid valve into the right ventricle, creating an 'atrialized' portion of the RV. Massive right atrial dilation, tricuspid regurgitation, and cardiomegaly. Associated with maternal lithium use.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-791", stem: "Congenital cystic adenomatoid malformation (CCAM/CPAM) of the fetal lung appears as:", options: ["Echogenic or cystic lung mass that may be microcystic (solid-appearing) or macrocystic, with possible mediastinal shift","Normal lung echotexture","Pleural effusion only","Absent lung tissue"], correctIndex: 0, rationale: "CCAM/CPAM is a hamartomatous lung lesion. Type I: large cysts (>2cm). Type II: smaller cysts (<2cm). Type III: microcystic/solid-appearing (echogenic). Large lesions cause mediastinal shift, hydrops, and polyhydramnios.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-792", stem: "Fetal bronchopulmonary sequestration on ultrasound appears as:", options: ["Echogenic, well-defined mass typically in the left lower lobe with a systemic arterial feeding vessel from the aorta on Doppler","Cystic lung lesion without blood supply","Bilateral pleural effusions","Normal lung tissue"], correctIndex: 0, rationale: "Pulmonary sequestration is a non-functioning lung mass with systemic arterial supply (usually from the aorta). It appears echogenic and homogeneous. Intralobar type is most common. Color Doppler identifies the feeding artery from the aorta.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-793", stem: "The normal umbilical cord contains:", options: ["Two arteries and one vein, surrounded by Wharton's jelly","One artery and one vein","Three arteries","Two veins and one artery"], correctIndex: 0, rationale: "Normal cord has two umbilical arteries (deoxygenated blood to placenta) and one umbilical vein (oxygenated blood to fetus), surrounded by Wharton's jelly. Single umbilical artery occurs in ~1% and may be associated with anomalies.", difficulty: 1, category: "OB/GYN Sonography", topic: "Umbilical Cord" },
  { id: "sono-794", stem: "Nuchal cord on ultrasound is identified by:", options: ["Color Doppler showing umbilical cord vessels encircling the fetal neck","B-mode showing a loop of cord at the feet","Increased amniotic fluid","Decreased fetal movement"], correctIndex: 0, rationale: "Nuchal cord is identified by color Doppler showing cord vessels around the fetal neck. Occurs in 20-30% of deliveries. Most are single loops and do not cause problems. Multiple tight loops may cause variable decelerations in labor.", difficulty: 1, category: "OB/GYN Sonography", topic: "Umbilical Cord" },
  { id: "sono-795", stem: "True knot of the umbilical cord on ultrasound shows:", options: ["A clover-leaf or four-leaf pattern on color Doppler where the cord overlaps and knots","Normal parallel cord vessels","Single coil of cord","Cord prolapse"], correctIndex: 0, rationale: "True knots occur in ~1% of pregnancies. On color Doppler, the cord appears to cross over itself, creating a knot pattern. Most are loose and asymptomatic, but tight knots can compromise fetal blood flow.", difficulty: 3, category: "OB/GYN Sonography", topic: "Umbilical Cord" },
  { id: "sono-796", stem: "The normal fetal cerebellum transverse diameter in millimeters approximately equals:", options: ["The gestational age in weeks from 14-22 weeks","Half the gestational age","Double the gestational age","The femur length in mm"], correctIndex: 0, rationale: "From 14-22 weeks, cerebellar transverse diameter in mm approximates gestational age in weeks (e.g., 18mm at 18 weeks). This relationship is useful for dating when other parameters are unreliable, as it is relatively resistant to growth restriction.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Biometry" },
  { id: "sono-797", stem: "Fetal echogenic kidneys bilaterally in the second trimester raise concern for:", options: ["Autosomal recessive polycystic kidney disease, trisomy 13, or CMV infection","Normal finding in all cases","Isolated pyelectasis","Posterior urethral valves"], correctIndex: 0, rationale: "Bilaterally echogenic fetal kidneys suggest ARPKD (especially if enlarged), trisomy 13 (especially with other markers), CMV infection, or other renal dysplasias. Assessment of amniotic fluid and other anomalies guides further evaluation.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-798", stem: "Fetal intracranial hemorrhage on ultrasound may show:", options: ["Echogenic focus within the ventricle (intraventricular hemorrhage) or parenchyma, with ventriculomegaly in severe cases","Normal brain anatomy","Absent cerebellum","Banana sign"], correctIndex: 0, rationale: "Fetal intracranial hemorrhage appears as echogenic material within ventricles or parenchyma. Severe IVH causes ventriculomegaly. Risk factors include fetal thrombocytopenia (alloimmune), maternal trauma, and fetomaternal hemorrhage.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-799", stem: "Meconium peritonitis on fetal ultrasound shows:", options: ["Intra-abdominal calcifications, ascites, and possible pseudocyst formation from bowel perforation in utero","Normal bowel pattern","Echogenic kidneys only","Dilated urinary tract"], correctIndex: 0, rationale: "Meconium peritonitis results from in-utero bowel perforation. Sterile meconium causes an inflammatory response with calcifications (bright peritoneal echoes), ascites, pseudocyst formation, and dilated bowel proximal to the perforation.", difficulty: 4, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-800", stem: "Fetal goiter on ultrasound appears as:", options: ["Bilobed solid mass in the anterior fetal neck at the level of the thyroid, potentially causing hyperextension and polyhydramnios","Posterior neck cystic mass","Intracranial mass","Abdominal mass"], correctIndex: 0, rationale: "Fetal goiter appears as a bilobed anterior neck mass. It may cause hyperextension of the fetal neck, obstructing swallowing and leading to polyhydramnios. Causes include maternal Graves disease treatment with PTU/methimazole or fetal hypothyroidism.", difficulty: 3, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-801", stem: "Sirenomelia (mermaid syndrome) on fetal ultrasound shows:", options: ["Fused lower extremities, renal agenesis, absent bladder, severe oligohydramnios, and single umbilical artery","Normal lower extremities with polyhydramnios","Bilateral clubfeet","Hydrops fetalis"], correctIndex: 0, rationale: "Sirenomelia is a rare lethal anomaly with fused lower extremities, absent/dysplastic kidneys, absent bladder, single umbilical artery, and severe oligohydramnios. It shares features with caudal regression syndrome.", difficulty: 5, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-802", stem: "Fetal ascites on ultrasound appears as:", options: ["Anechoic fluid surrounding the abdominal organs, visible between the liver edge and abdominal wall","Echogenic bowel","Solid abdominal mass","Normal abdominal finding"], correctIndex: 0, rationale: "Fetal ascites appears as anechoic fluid around abdominal organs. Isolated ascites may be from urinary tract obstruction or meconium peritonitis. When part of hydrops (≥2 fluid collections), it suggests more systemic causes.", difficulty: 1, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-803", stem: "Cervical incompetence on ultrasound is best evaluated by:", options: ["Transvaginal ultrasound showing progressive cervical shortening and funneling of the internal os","Transabdominal ultrasound at 36 weeks","MRI only","Clinical exam alone"], correctIndex: 0, rationale: "Cervical incompetence is painless cervical dilation. TVS shows short cervix (<25mm), funneling, and dynamic changes with fundal pressure. Serial cervical length measurements identify patients who may benefit from cerclage.", difficulty: 2, category: "OB/GYN Sonography", topic: "Cervical Assessment" },
  { id: "sono-804", stem: "Fetal nuchal fold thickness measured in the second trimester >6mm is associated with:", options: ["Trisomy 21 (Down syndrome)","Neural tube defects","Cardiac defects only","Normal variant"], correctIndex: 0, rationale: "Nuchal fold thickness >6mm measured between 15-22 weeks at the level of the posterior fossa is one of the strongest second-trimester markers for trisomy 21 (LR+ ~11). It differs from first-trimester nuchal translucency.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
  { id: "sono-805", stem: "Fetal pleural effusion on ultrasound appears as:", options: ["Anechoic fluid surrounding the lung, displacing the lung medially, seen between the chest wall and lung","Solid chest wall mass","Echogenic lungs","Normal pulmonary anatomy"], correctIndex: 0, rationale: "Fetal pleural effusion appears as fluid between the lung and chest wall, displacing the lung medially. Primary (chylothorax) or secondary (hydrops, infection, cardiac failure). Large effusions cause mediastinal shift and pulmonary hypoplasia.", difficulty: 2, category: "OB/GYN Sonography", topic: "Fetal Anomalies" },
];
